  1→// src/features/browser/automation/visual-effects.ts
  2→// Re-exports the compiled visual effects IIFE + builder functions.
  3→//
  4→// The source TypeScript lives in inject/visual-effects.ts with full IDE support.
  5→// It's compiled by build-inject.ts (esbuild) into dist-inject/visual-effects.js.
  6→//
  7→// To modify visual effects behavior, edit inject/visual-effects.ts and
  8→// run `bun run build:inject` to recompile.
  9→//
 10→// Builder functions (buildMoveCursorAndRippleJs, etc.) stay here because they're
 11→// TypeScript functions that parameterize small runtime snippets — not worth extracting.
 12→
 13→/** The IIFE string to eval in WKWebView — sets up visual effects infrastructure. */
 14→import VISUAL_EFFECTS_SETUP from './dist-inject/visual-effects.js?raw';
 15→export { VISUAL_EFFECTS_SETUP };
 16→
 17→/**
 18→ * Build JS to move cursor to an element by data-opendevs-ref,
 19→ * then ripple on arrival (used before click actions).
 20→ * Returns duration (ms) via title-channel so frontend can wait.
 21→ */
 22→export function buildMoveCursorAndRippleJs(ref: string): string {
 23→  return `(function(){
 24→  if (!window.__opendevsVisuals) return JSON.stringify({duration:0});
 25→  var el = document.querySelector('[data-opendevs-ref="${ref}"]');
 26→  if (!el) return JSON.stringify({duration:0, error:'Element not found'});
 27→  var dur = window.__opendevsVisuals.moveCursorToElement(el);
 28→  // Ripple after cursor arrives
 29→  setTimeout(function(){
 30→    var rect = el.getBoundingClientRect();
 31→    var cx = Math.round(rect.left + rect.width / 2);
 32→    var cy = Math.round(rect.top + rect.height / 2);
 33→    window.__opendevsVisuals.rippleAt(cx, cy);
 34→  }, dur + 20);
 35→  return JSON.stringify({duration: dur + 280});
 36→})()`;
 37→}
 38→
 39→/**
 40→ * Build JS to move cursor to an element and pin it (for typing).
 41→ */
 42→export function buildPinCursorJs(ref: string): string {
 43→  return `(function(){
 44→  if (!window.__opendevsVisuals) return JSON.stringify({duration:0});
 45→  var el = document.querySelector('[data-opendevs-ref="${ref}"]');
 46→  if (!el) return JSON.stringify({duration:0, error:'Element not found'});
 47→  var dur = window.__opendevsVisuals.moveCursorToElement(el);
 48→  setTimeout(function(){
 49→    window.__opendevsVisuals.pinCursorToElement(el);
 50→  }, dur + 20);
 51→  return JSON.stringify({duration: dur + 20});
 52→})()`;
 53→}
 54→
 55→/** Build JS to unpin and hide cursor (after typing finishes) */
 56→export const HIDE_CURSOR_JS = `(function(){
 57→  if (window.__opendevsVisuals) window.__opendevsVisuals.hideCursor();
 58→})()`;
 59→
 60→/**
 61→ * Build JS to fade cursor out gracefully after a dwell period.
 62→ * Used after click/hover — cursor lingers so user sees where AI interacted,
 63→ * then fades out smoothly. Default dwell: 600ms.
 64→ */
 65→export function buildFadeCursorJs(dwellMs = 1000): string {
 66→  return `(function(){
 67→  if (window.__opendevsVisuals) window.__opendevsVisuals.fadeCursor(${dwellMs});
 68→})()`;
 69→}
 70→
 71→/**
 72→ * Build JS for screenshot flash effect.
 73→ * If rect is provided, flashes only that region; otherwise flashes full viewport.
 74→ */
 75→export function buildScreenshotFlashJs(rect?: {
 76→  x: number;
 77→  y: number;
 78→  width: number;
 79→  height: number;
 80→}): string {
 81→  const rectArg = rect
 82→    ? `{x:${rect.x},y:${rect.y},width:${rect.width},height:${rect.height}}`
 83→    : "null";
 84→  return `(function(){
 85→  if (window.__opendevsVisuals) window.__opendevsVisuals.screenshotFlash(${rectArg});
 86→})()`;
 87→}
 88→
 89→/**
 90→ * Build JS for element highlight effect (blue outline pulse).
 91→ * Used to show which element the AI is inspecting/screenshotting.
 92→ */
 93→export function buildHighlightElementJs(ref: string): string {
